public int caughtSpeeding(int speed, boolean isBirthday) {
    int normalLimit = 60;
    int smallTicketLimit = 80;

    if (isBirthday) {
        normalLimit += 5;
        smallTicketLimit += 5;
    }

    if (speed <= normalLimit) {
        return 0;
    } else if (speed >= normalLimit + 1 && speed <= smallTicketLimit) {
        return 1;
    } else {
        return 2;
    }
}

